declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/comunicacion_centro.php';exigirAutenticacion();$id=filter_var($_GET['id']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$pdo=obtenerConexion();$q=$pdo->prepare("SELECT a.*,m.conversacion_id FROM chat_adjuntos a JOIN chat_mensajes m ON m.id=a.mensaje_id WHERE a.id=:id AND m.estado='activo'");$q->execute(['id'=>$id]);$a=$q->fetch();if(!$a||!chatParticipa($pdo,(int)$a['conversacion_id'],(int)$_SESSION['usuario_id']))mostrarPaginaErrorAtenea(404);$ruta=rutaPrivadaComunicacion((string)$a['archivo_relpath']);if(!$ruta)mostrarPaginaErrorAtenea(404);$inline=!empty($a['es_imagen']);header('Content-Type: '.$a['archivo_mime']);header('Content-Length: '.filesize($ruta));header('X-Content-Type-Options: nosniff');header('Cache-Control: private, max-age=300');header('Content-Disposition: '.($inline?'inline':'attachment').'; filename="'.str_replace(['"',"\r","\n"],'',(string)$a['archivo_nombre']).'"');readfile($ruta);exit;
